### 5. Optional: Deploy a Cloud Function for Custom Validation

Create a **Node.js** function that checks request limits:
```javascript
const functions = require('firebase-functions');
const admin = require('firebase-admin');
admin.initializeApp();
```

exports.validatePhoneRequest = functions.https.onCall(async (data, context) => {
  const { phoneNumber } = data;
  const now = admin.firestore.Timestamp.now();
  const docRef = admin.firestore().collection('otp_requests').doc(phoneNumber);
  const doc = await docRef.get();
  if (doc.exists && now.seconds - doc.data().lastRequested < 60) {
    throw new functions.https.HttpsError('resource-exhausted', 'Too many requests. Try again later.');
  }
  await docRef.set({ lastRequested: now }, { merge: true });
  return { status: 'ok' };
});

