### 3. Token Generation Logic

```js
// tokenService.js
const fs = require('fs');
const jwt = require('jsonwebtoken');
const { v4: uuidv4 } = require('uuid');
```

const privateKey = fs.readFileSync(process.env.PRIVATE_KEY);
const publicKey = fs.readFileSync(process.env.PUBLIC_KEY);

function signAccessToken(payload) {
  return jwt.sign(payload, privateKey, {
    algorithm: 'RS256',
    expiresIn: process.env.ACCESS_TOKEN_TTL,
    jwtid: uuidv4() // unique identifier for revocation
  });
}

function signRefreshToken(payload) {
  return jwt.sign(payload, privateKey, {
    algorithm: 'RS256',
    expiresIn: process.env.REFRESH_TOKEN_TTL,
    jwtid: uuidv4()
  });
}

function verifyToken(token) {
  try {
    return jwt.verify(token, publicKey, { algorithms: ['RS256'] });
  } catch (err) {
    return null; // caller will handle invalid token
  }
}

module.exports = { signAccessToken, signRefreshToken, verifyToken };

### 4. Login Endpoint

```js
// authRoutes.js
const express = require('express');
const bcrypt = require('bcryptjs');
const { users } = require('./users');
const { signAccessToken, signRefreshToken } = require('./tokenService');
```

const router = express.Router();

router.post('/login', async (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username);
  if (!user) return res.status(401).json({ message: 'Invalid credentials' });

  const passwordMatch = await bcrypt.compare(password, user.passwordHash);
  if (!passwordMatch) return res.status(401).json({ message: 'Invalid credentials' });

  const accessToken = signAccessToken({ sub: user.id, role: user.role });
  const refreshToken = signRefreshToken({ sub: user.id });

  // Securely set HttpOnly cookie for refresh token
  res.cookie('refreshToken', refreshToken, {
    httpOnly: true,
    secure: true,
    sameSite: 'strict',
    maxAge: 7 * 24 * 60 * 60 * 1000 // 7 days in ms
  });

  res.json({ accessToken });
});

module.exports = router;

### 5. Refresh Endpoint

```js
router.post('/refresh', (req, res) => {
  const { refreshToken } = req.cookies;
  if (!refreshToken) return res.status(401).json({ message: 'Refresh token missing' });
```

  const decoded = verifyToken(refreshToken);
  if (!decoded) return res.status(401).json({ message: 'Invalid refresh token' });

  // Issue a new access token; keep the same subject and role
  const user = users.find(u => u.id === decoded.sub);
  if (!user) return res.status(401).json({ message: 'User not found' });

  const newAccessToken = signAccessToken({ sub: user.id, role: user.role });
  res.json({ accessToken: newAccessToken });
});

With these routes, the token service can **issue**, **refresh**, and **verify** JWTs while keeping private keys isolated from the rest of the application.

Once the token service is operational, every protected route must ensure that a valid access token accompanies the request. The typical pattern is a **middleware** that extracts the token, validates it, and attaches the decoded payload to `req.user` for downstream handlers.

### Middleware Implementation

```js
// authMiddleware.js
const { verifyToken } = require('./tokenService');
```

function authenticate(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer <token>
  if (!token) return res.sendStatus(401);

  const payload = verifyToken(token);
  if (!payload) return res.sendStatus(403); // token invalid or expired

  // Attach user info to the request object
  req.user = {
    id: payload.sub,
    role: payload.role,
    jti: payload.jti
  };
  next();
}

module.exports = { authenticate };

### Role‑Based Access Control (RBAC)

For APIs that expose different functionalities based on user roles, add a simple **authorization** layer.

```js
function authorize(allowedRoles = []) {
  return (req, res, next) => {
    if (!allowedRoles.includes(req.user.role)) {
      return res.sendStatus(403);
    }
    next();
  };
}
```

module.exports = { authorize };

