### Token Revocation Strategy

Although JWTs are stateless, revocation is achievable by storing **revoked `jti` values** in a fast data store (e.g., Redis) with an expiration equal to the token's TTL.

```js
// revocationService.js (simplified)
const redis = require('redis');
const client = redis.createClient();
```

async function revokeToken(jti, ttlSeconds) {
  await client.setex(`revoked:${jti}`, ttlSeconds, 'true');
}

async function isTokenRevoked(jti) {
  const result = await client.get(`revoked:${jti}`);
  return result === 'true';
}

module.exports = { revokeToken, isTokenRevoked };

Integrate the check into the authentication middleware:

```js
const { isTokenRevoked } = require('./revocationService');
```

async function authenticate(req, res, next) {
  // ... token extraction & verification as before
  const payload = verifyToken(token);
  if (!payload) return res.sendStatus(403);

  const revoked = await isTokenRevoked(payload.jti);
  if (revoked) return res.sendStatus(401);

  // continue with attaching user
  req.user = { id: payload.sub, role: payload.role, jti: payload.jti };
  next();
}

By doing so, compromised tokens can be invalidated instantly without waiting for natural expiration.

### Security Best Practices Checklist

* **Use asymmetric keys (RS256)** - Allows key rotation without downtime.
* **Set short access‑token lifetimes** - Limits exposure if a token is stolen.
* **Store refresh tokens in HttpOnly, Secure cookies** - Prevents XSS access.
* **Validate `aud` and `iss` claims** - Guarantees token originates from your service.
* **Enable CORS with strict origins** - Avoids CSRF attacks.
* **Log authentication events** - Helps with forensic analysis.

Following these practices ensures a resilient authentication layer that scales across microservices.

Below are two self‑contained examples that illustrate how to wire the PDP into an Express API (Node.js) and a Flask service (Python). Both consume the same `roles` and `permissions` schema described earlier.

### Node.js - Express Middleware (PDP)

```js
// rbacPdp.js
const { Pool } = require('pg');
const jwt = require('jsonwebtoken');
```

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

/** Resolve permissions for a set of role IDs, including inherited roles */
async function resolvePermissions(roleIds) {
  const query = `
    WITH RECURSIVE role_tree AS (
      SELECT id, parent_id FROM roles WHERE id = ANY($1)
      UNION ALL
      SELECT r.id, r.parent_id
      FROM roles r
      JOIN role_tree rt ON r.id = rt.parent_id
    )
    SELECT DISTINCT p.action, p.resource
    FROM role_tree rt
    JOIN role_permission rp ON rp.role_id = rt.id
    JOIN permissions p ON p.id = rp.permission_id;
  `;
  const { rows } = await pool.query(query, [roleIds]);
  return rows.map(r => `${r.action}:${r.resource}`);
}

/** Express middleware acting as PDP */
module.exports = async function rbacPdp(req, res, next) {
  try {
    const authHeader = req.headers['authorization'];
    if (!authHeader) return res.sendStatus(401);
    const token = authHeader.split(' ')[1];
    const payload = jwt.verify(token, process.env.JWT_SECRET);
    const roleIds = payload.roles; // array of role DB IDs

    const permissions = await resolvePermissions(roleIds);
    const required = `${req.method.toLowerCase()}:${req.baseUrl}${req.path}`;

    // Simple contextual constraint example (business hours only)
    const hour = new Date().getHours();
    if (hour < 9 || hour > 18) {
      return res.status(403).json({ error: 'Access restricted to business hours' });
    }

    if (permissions.includes(required)) {
      return next();
    }
    return res.sendStatus(403);
  } catch (err) {
    console.error(err);
    return res.sendStatus(403);
  }
};

