### Python - Flask Extension (PDP)

python
# rbac_pdp.py
import os
import jwt
import psycopg2
from flask import request, jsonify

conn = psycopg2.connect(os.getenv('DATABASE_URL'))

def get_permissions(role_ids):
    with conn.cursor() as cur:
        cur.execute('''
            WITH RECURSIVE role_tree AS (
                SELECT id, parent_id FROM roles WHERE id = ANY(%s)
                UNION ALL
                SELECT r.id, r.parent_id
                FROM roles r
                JOIN role_tree rt ON r.id = rt.parent_id
            )
            SELECT DISTINCT p.action, p.resource
            FROM role_tree rt
            JOIN role_permission rp ON rp.role_id = rt.id
            JOIN permissions p ON p.id = rp.permission_id;
        ''', (role_ids,))
        rows = cur.fetchall()
    return {f"{a}:{r}" for a, r in rows}

def rbac_pdp(required_action):
    def decorator(fn):
        def wrapper(*args, **kwargs):
            auth = request.headers.get('Authorization', None)
            if not auth:
                return jsonify({'error': 'Missing token'}), 401
            try:
                token = auth.split()[1]
                payload = jwt.decode(token, os.getenv('JWT_SECRET'), algorithms=['HS256'])
                role_ids = payload.get('roles', [])
                perms = get_permissions(role_ids)
                # Business‑hour constraint
                if not (9 <= datetime.utcnow().hour <= 18):
                    return jsonify({'error': 'Access outside business hours'}), 403
                if required_action not in perms:
                    return jsonify({'error': 'Forbidden'}), 403
            except Exception as e:
                return jsonify({'error': str(e)}), 403
            return fn(*args, **kwargs)
        wrapper.__name__ = fn.__name__
        return wrapper
    return decorator

**Applying the decorator**

python
