Below we walk through a Node.js/Express implementation that follows the architecture laid out earlier. The example focuses on a product catalog where users can filter by category, price range, rating, tags, and full‑text search.

### 1. Validation Layer (Zod Example)

ts
import { z } from 'zod';

export const productFilterSchema = z.object({
  category: z.string().optional(),
  minPrice: z.number().min(0).optional(),
  maxPrice: z.number().min(0).optional(),
  rating: z.enum(['1', '2', '3', '4', '5']).optional(),
  tags: z.array(z.string()).optional(),
  search: z.string().min(3).optional(),
  page: z.number().int().min(1).default(1),
  pageSize: z.number().int().min(1).max(100).default(20)
});

The schema guarantees that numeric bounds are non‑negative and that the `search` term meets a minimum length, preventing expensive wildcard scans.

### 2. Dynamic Query Builder

ts
import { FilterQuery } from 'mongodb';

function buildPipeline(params: any): any[] {
  const pipeline: any[] = [];

  // 1️⃣ Text search (Atlas Search) - runs first for maximum selectivity
  if (params.search) {
    pipeline.push({
      $search: {
        index: 'productSearch',
        text: {
          query: params.search,
          path: ['title', 'description', 'tags']
        }
      }
    });
  }

  // 2️⃣ Match stage for exact / range filters
  const match: FilterQuery<any> = {};
  if (params.category) match.category = params.category;
  if (params.rating) match.rating = Number(params.rating);
  if (params.minPrice !== undefined || params.maxPrice !== undefined) {
    match.price = {};
    if (params.minPrice !== undefined) match.price.$gte = params.minPrice;
    if (params.maxPrice !== undefined) match.price.$lte = params.maxPrice;
  }
  if (params.tags?.length) match.tags = { $all: params.tags };

  if (Object.keys(match).length) pipeline.push({ $match: match });

  // 3️⃣ Facet for aggregating filter metadata (e.g., total count, price histogram)
  pipeline.push({
    $facet: {
      metadata: [{ $count: 'total' }],
      results: [
        { $sort: { rating: -1, price: 1 } },
        { $skip: (params.page - 1) * params.pageSize },
        { $limit: params.pageSize },
        { $project: { _id: 0, title: 1, price: 1, rating: 1, tags: 1 } }
      ]
    }
  });

  // 4️⃣ Unwind metadata to a friendly shape
  pipeline.push({
    $addFields: {
      total: { $arrayElemAt: ['$metadata.total', 0] }
    }
  }, {
    $project: { metadata: 0 }
  });

  return pipeline;
}

Key points:
- `$search` runs before `$match` to shrink the working set.
- A **compound index** on `{ category: 1, price: 1, rating: -1 }` supports the subsequent `$match` and `$sort` stages when the search stage is omitted.
- `$facet` gives us pagination results **and** total count in a single round‑trip.

### 3. Service Handler (Express Route)

ts
import express from 'express';
import { productFilterSchema } from './validation.js';
import { buildPipeline } from './pipeline.js';
import { getMongoCollection } from './mongoClient.js';

const router = express.Router();

router.get('/products', async (req, res) => {
  // Validate query parameters
  const parseResult = productFilterSchema.safeParse(req.query);
  if (!parseResult.success) {
    return res.status(400).json({ error: parseResult.error.format() });
  }
  const params = parseResult.data;

  // Build aggregation pipeline
  const pipeline = buildPipeline(params);

  try {
    const collection = await getMongoCollection('products');
    const [result] = await collection.aggregate(pipeline).toArray();

    // Optional: Cache result in Redis for identical query string
    // await redis.setex(cacheKey, 60, JSON.stringify(result));

    res.json({
      page: params.page,
      pageSize: params.pageSize,
      total: result.total || 0,
      data: result.results
    });
  } catch (err) {
    console.error('Filtering error:', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

export default router;

