  "ci": {
    "collect": {
      "url": ["https://example.com"],
      "numberOfRuns": 5,
      "settings": {"preset": "desktop", "maxWaitForFcp": 15000}
    },
    "assert": {
      "preset": "lighthouse:recommended",
      "assertions": {
        "first-contentful-paint": ["error", {"maxNumericValue": 2000}],
