## Writing a Vendor Adapter (Python/Requests)

python
import requests
from typing import Dict, Any

class VendorAAdapter:
    def __init__(self, base_url: str, api_key: str):
        self.base_url = base_url.rstrip('/')
        self.headers = {
            "Authorization": f"Bearer {api_key}",
            "Content-Type": "application/json"
        }

    def reserve_inventory(self, order: Dict[str, Any]) -> Dict[str, Any]:
        payload = {
            "sku": order["product_sku"],
            "quantity": order["quantity"]
        }
        response = requests.post(
            f"{self.base_url}/inventory/reserve",
            json=payload,
            headers=self.headers,
            timeout=5
        )
        response.raise_for_status()
        return response.json()

# Usage example
if __name__ == "__main__":
    adapter = VendorAAdapter("https://api.vendor-a.com", "YOUR_API_KEY")
    order = {"product_sku": "ABC123", "quantity": 2}
    result = adapter.reserve_inventory(order)
    print("Reservation response:", result)

The adapter isolates all vendor‑specific details, exposing a simple method that the orchestration layer can call.

## Orchestration with Temporal (Go SDK)

go
package workflows

import (
    "go.temporal.io/sdk/workflow"
    "go.temporal.io/sdk/activity"
)

type Order struct {
    ID          string
    SKU         string
    Quantity    int
    PaymentInfo struct {
        CardNumber string
        Expiry     string
        CVC        string
    }
}

func OrderWorkflow(ctx workflow.Context, order Order) error {
    ao := workflow.ActivityOptions{Timeout: workflow.DefaultActivityOptions().StartToCloseTimeout * 2}
    ctx = workflow.WithActivityOptions(ctx, ao)

    // Parallel execution: reserve inventory and process payment
    futures := []workflow.Future{
        workflow.ExecuteActivity(ctx, ReserveInventory, order),
        workflow.ExecuteActivity(ctx, ProcessPayment, order),
    }

    // Wait for both to finish
    for _, f := range futures {
        if err := f.Get(ctx, nil); err != nil {
            // Compensation logic if any activity fails
            workflow.ExecuteActivity(ctx, CancelReservation, order).Get(ctx, nil)
            return err
        }
    }
    return nil
}

func ReserveInventory(ctx context.Context, order Order) error {
    // Call Vendor A Adapter via HTTP - omitted for brevity
    return activity.ExecuteActivity(ctx, "VendorAAdapter.reserve_inventory", order).Get(ctx, nil)
}

func ProcessPayment(ctx context.Context, order Order) error {
    // Call Vendor B Adapter - omitted for brevity
    return activity.ExecuteActivity(ctx, "VendorBAdapter.process_payment", order).Get(ctx, nil)
}

