### State Management with Redux Toolkit

A slice encapsulates product state, selectors, and reducers in a single file.

ts
// src/presentation/store/productSlice.ts
import {createSlice, PayloadAction} from '@reduxjs/toolkit';
import {Product} from '../../domain/models/Product';
import {fetchProducts} from '../../domain/usecases/productUsecase';

interface ProductState {
  products: Product[];
  loading: boolean;
  error?: string;
}

const initialState: ProductState = {
  products: [],
  loading: false,
};

const productSlice = createSlice({
  name: 'product',
  initialState,
  reducers: {},
  extraReducers: builder => {
    builder
      .addCase(fetchProducts.pending, state => {
        state.loading = true;
        state.error = undefined;
      })
      .addCase(fetchProducts.fulfilled, (state, action: PayloadAction<Product[]>) => {
        state.loading = false;
        state.products = action.payload;
      })
      .addCase(fetchProducts.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload as string;
      });
  },
});

export default productSlice.reducer;

The slice is then added to the store root reducer.

ts
// src/presentation/store/index.ts
import {configureStore} from '@reduxjs/toolkit';
import productReducer from './productSlice';

export const store = configureStore({
  reducer: {
    product: productReducer,
  },
});

export type RootState = ReturnType<typeof store.getState>;
export type AppDispatch = typeof store.dispatch;

