### 4. `server.js`

```js
// Enable ES6/JSX syntax on the fly
require("@babel/register")({ extensions: [".js", ".jsx"] });
```

const path = require("path");
const express = require("express");
const React = require("react");
const ReactDOMServer = require("react-dom/server");
const App = require("./src/App.jsx").default;
const { fetchGreeting } = require("./src/App.jsx");

const app = express();
const PORT = process.env.PORT || 3000;

// Serve static assets (client bundle, CSS, etc.)
app.use("/static", express.static(path.resolve(__dirname, "static")));

app.get("/:name?", async (req, res) => {
  const name = req.params.name || "World";

  // 1️⃣ Fetch data before rendering
  const greeting = await fetchGreeting(name);

  // 2️⃣ Render React component to a string
  const appHtml = ReactDOMServer.renderToString(
    React.createElement(App, { greeting })
  );

  // 3️⃣ Read the HTML template
  const templatePath = path.resolve(__dirname, "public/index.html");
  let template = require("fs").readFileSync(templatePath, "utf8");

  // 4️⃣ Inject the rendered markup and serialized state
  template = template.replace("<!--{{SSR_CONTENT}}-->", appHtml);
  template = template.replace(
    "{{INITIAL_DATA}}",
    JSON.stringify({ greeting })
  );

  // 5️⃣ Send the complete HTML page
  res.send(template);
});

app.listen(PORT, () => {
  console.log(`🚀 SSR server running at http://localhost:${PORT}`);
});

