        cursor = await db.execute("SELECT id, name, price FROM product")
        rows = await cursor.fetchall()
        return [{"id": r[0], "name": r[1], "price": r[2]} for r in rows]

@app.post("/products")
async def create_product(p: Product):
    async with (await get_db()) as db:
        cur = await db.execute(
            "INSERT INTO product (name, price) VALUES (?, ?)", (p.name, p.price)
        )
        await db.commit()
        pid = cur.lastrowid
