// Verify OTP endpoint
router.post(
  '/verify',
  rateLimiter,
  body('verificationId').isString(),
  body('code').isLength({ min: 6, max: 6 }),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const { verificationId, code, phoneNumber } = req.body;
    try {
