### 3. Redis Helper for Permission Caching

typescript
// src/cache/PermissionCache.ts
import {createClient, RedisClientType} from 'redis';
import {Permission} from '../entity/Permission';

class PermissionCache {
  private client: RedisClientType;

  constructor() {
    this.client = createClient({url: process.env.REDIS_URL});
    this.client.connect().catch(console.error);
  }

  async getPermissionsForRole(roleId: string): Promise<string[]> {
    const key = `rbac:role:${roleId}`;
    const cached = await this.client.get(key);
    if (cached) {
      return JSON.parse(cached);
    }
    // Fallback - load from DB (caller must provide repository)
    return [];
  }

  async setPermissionsForRole(roleId: string, perms: string[]) {
    const key = `rbac:role:${roleId}`;
    await this.client.set(key, JSON.stringify(perms), {EX: 3600}); // 1‑hour TTL
    await this.client.publish('rbac:invalidate', roleId);
  }

  async invalidateRole(roleId: string) {
    const key = `rbac:role:${roleId}`;
    await this.client.del(key);
  }
}

export const permissionCache = new PermissionCache();

