## Building the Aggregation Pipeline

The `FilterService` receives the validated filter object and assembles an array of pipeline stages.

```js
// filterService.js
const Product = require('../models/Product');
```

function buildPipeline(filters) {
  const pipeline = [];

  // 1️⃣ Text Search (if provided)
  if (filters.search) {
    pipeline.push({
      $match: { $text: { $search: filters.search } }
    });
    // Add a relevance score field for sorting if needed
    pipeline.push({ $addFields: { relevance: { $meta: 'textScore' } } });
  }

  // 2️⃣ Numeric Range Filters (price)
  if (filters.price) {
    const priceMatch = {};
    if (filters.price.min !== undefined) priceMatch.$gte = filters.price.min;
    if (filters.price.max !== undefined) priceMatch.$lte = filters.price.max;
    pipeline.push({ $match: { price: priceMatch } });
  }

  // 3️⃣ Category - array contains
  if (filters.category && filters.category.length) {
    pipeline.push({ $match: { category: { $in: filters.category } } });
  }

  // 4️⃣ Rating - greater‑than or equal
  if (filters.rating && filters.rating.gte !== undefined) {
    pipeline.push({ $match: { rating: { $gte: filters.rating.gte } } });
  }

  // 5️⃣ Boolean flag - inStock
  if (typeof filters.inStock === 'boolean') {
    pipeline.push({ $match: { inStock: filters.inStock } });
  }

  // 6️⃣ Sorting - default to createdAt desc
  const sortField = (filters.sort && filters.sort.field) || (filters.search ? 'relevance' : 'createdAt');
  const sortOrder = (filters.sort && filters.sort.order === 'asc') ? 1 : -1;
  pipeline.push({ $sort: { [sortField]: sortOrder } });

  // 7️⃣ Facet - total count + paginated results in one round‑trip
  const page = Math.max(1, parseInt(filters.page, 10) || 1);
  const limit = Math.max(1, parseInt(filters.limit, 10) || 20);
  const skip = (page - 1) * limit;

  pipeline.push({
    $facet: {
      metadata: [{ $count: 'total' }],
      data: [{ $skip: skip }, { $limit: limit }]
    }
  });

  // 8️⃣ Project - reshape response for API consumer
  pipeline.push({
    $project: {
      data: 1,
      total: { $arrayElemAt: ['$metadata.total', 0] },
      page: page,
      limit: limit,
      pages: {
        $ceil: { $divide: [{ $ifNull: [{ $arrayElemAt: ['$metadata.total', 0] }, 0] }, limit] }
      }
    }
  });

  return pipeline;
}

async function getFilteredProducts(filters) {
  const pipeline = buildPipeline(filters);
  const [result] = await Product.aggregate(pipeline).exec();
  return result;
}

module.exports = { getFilteredProducts };

### Explanation of Key Stages

- **$match** - Incrementally narrows the dataset. Each conditional block adds a new `$match` only when the corresponding filter is present, keeping the pipeline lightweight.
- **$addFields (relevance)** - When a text search is active, MongoDB provides a relevance score via `$meta: 'textScore'`. Adding it as a field enables sorting by relevance without extra queries.
- **$facet** - Allows us to compute the total document count (`metadata`) and the paginated slice (`data`) in a single aggregation. This eliminates the classic *count + find* two‑query pattern.
- **$project** - Normalizes the response structure, guaranteeing fields like `total`, `page`, `pages`, and `limit` are always present.

