// Validation schema matching the filter contract
const filterSchema = Joi.object({
  search: Joi.string().allow('', null),
  price: Joi.object({ min: Joi.number(), max: Joi.number() }).allow(null),
  category: Joi.array().items(Joi.string()),
  rating: Joi.object({ gte: Joi.number().min(0).max(5) }).allow(null),
  inStock: Joi.boolean(),
  sort: Joi.object({ field: Joi.string(), order: Joi.string().valid('asc', 'desc') }).allow(null),
  page: Joi.number().integer().min(1).default(1),
  limit: Joi.number().integer().min(1).max(100).default(20)
});

router.post('/search', async (req, res) => {
  const { error, value: filters } = filterSchema.validate(req.body);
  if (error) return res.status(400).json({ message: error.details[0].message });

  try {
    const result = await getFilteredProducts(filters);
    res.json(result);
  } catch (err) {
    console.error('Filtering error:', err);
    res.status(500).json({ message: 'Internal server error' });
  }
});

module.exports = router;

### What This Route Does
1. **Validates** the incoming payload against `filterSchema`.
2. **Calls** `getFilteredProducts`, which builds and executes the aggregation pipeline.
3. **Returns** a JSON payload containing `data`, `total`, `page`, `limit`, and `pages`.

