## Programmatic Index Creation with the Native Driver

```javascript
// createIndexes.js
const { MongoClient } = require('mongodb');
```

async function createIndexes(uri) {
  const client = new MongoClient(uri, { useUnifiedTopology: true });
  await client.connect();
  const db = client.db('ecommerce');

  // Orders collection - compound index
  await db.collection('orders').createIndex(
    { userId: 1, status: 1, orderDate: -1 },
    { name: 'idx_user_status_date' }
  );

  // Products collection - text index
  await db.collection('products').createIndex(
    { name: 'text', description: 'text' },
    { name: 'idx_product_text', default_language: 'english' }
  );

  // Sessions collection - TTL index
  await db.collection('sessions').createIndex(
    { expiresAt: 1 },
    { expireAfterSeconds: 0, name: 'ttl_sessions' }
  );

  console.log('Indexes created successfully');
  await client.close();
}

createIndexes('mongodb://localhost:27017').catch(console.error);

