### 3. Authentication Middleware (src/middlewares/auth.middleware.ts)
typescript
import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';

declare global {
  namespace Express { interface Request { user?: any } }
}

export const authenticate = (req: Request, res: Response, next: NextFunction) => {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith('Bearer ')) {
    return res.sendStatus(401);
  }
  const token = authHeader.split(' ')[1];
  try {
    const payload = jwt.verify(token, process.env.JWT_SECRET!);
    req.user = payload;
    next();
  } catch (e) {
    return res.sendStatus(403);
  }
};

### 4. Service Layer (src/services/product.service.ts)
typescript
import { query } from '../db';
import { Product } from '../types';

export class ProductService {
  static async getById(id: number): Promise<Product | null> {
    const { rows } = await query('SELECT * FROM products WHERE id = $1', [id]);
    return rows[0] || null;
  }

  static async create(data: Partial<Product>): Promise<Product> {
    const { rows } = await query(
      `INSERT INTO products (name, description, price, stock)
       VALUES ($1, $2, $3, $4)
       RETURNING *`,
      [data.name, data.description, data.price, data.stock]
    );
    return rows[0];
  }

  static async list(limit: number, cursor?: string): Promise<{ items: Product[]; nextCursor?: string }> {
    let queryText = 'SELECT * FROM products ORDER BY id ASC LIMIT $1';
    const params: any[] = [limit + 1]; // fetch one extra to know if there is a next page
    if (cursor) {
      const decoded = Buffer.from(cursor, 'base64').toString('utf8');
      const lastId = JSON.parse(decoded).id;
      queryText = 'SELECT * FROM products WHERE id > $2 ORDER BY id ASC LIMIT $1';
      params.push(lastId);
    }
    const { rows } = await query(queryText, params);
    const hasNext = rows.length > limit;
    const items = hasNext ? rows.slice(0, -1) : rows;
    const nextCursor = hasNext ? Buffer.from(JSON.stringify({ id: items[items.length - 1].id })).toString('base64') : undefined;
    return { items, nextCursor };
  }
}

### 5. Controller (src/controllers/product.controller.ts)
typescript
import { Request, Response } from 'express';
import { ProductService } from '../services/product.service';

export class ProductController {
  static async getProduct(req: Request, res: Response) {
    const product = await ProductService.getById(parseInt(req.params.id, 10));
    if (!product) return res.sendStatus(404);
    res.json(product);
  }

  static async createProduct(req: Request, res: Response) {
    const product = await ProductService.create(req.body);
    res.status(201).json(product);
  }

  static async listProducts(req: Request, res: Response) {
    const limit = Math.min(parseInt(req.query.limit as string) || 20, 100);
    const cursor = req.query.cursor as string | undefined;
    const { items, nextCursor } = await ProductService.list(limit, cursor);
    res.json({ items, nextCursor });
  }
}

