## 4. Rate Limiting & Abuse Prevention

```js
// functions/src/rateLimit.ts
import * as admin from "firebase-admin";
const db = admin.firestore();
```

export async function canRequestOTP(phone: string): Promise<boolean> {
  const docRef = db.collection('otp_requests').doc(phone);
  const doc = await docRef.get();
  const now = admin.firestore.Timestamp.now();

  if (!doc.exists) {
    await docRef.set({ count: 1, lastRequest: now });
    return true;
  }

  const data = doc.data()!;
  const diff = now.seconds - data.lastRequest.seconds;
  // Reset count after 1 hour
  if (diff > 3600) {
    await docRef.set({ count: 1, lastRequest: now });
    return true;
  }

  if (data.count >= 5) {
    return false; // Exceeded limit
  }

  await docRef.update({ count: admin.firestore.FieldValue.increment(1), lastRequest: now });
  return true;
}

Integrate `canRequestOTP` before invoking `signInWithPhoneNumber` on the client (via a callable function) to ensure the user stays within safe thresholds.

By following these snippets, developers can create a robust OTP flow that balances convenience with strong security controls.

