## Caching Identical Queries

```js
const redis = require('redis');
const redisClient = redis.createClient();
```

async function cachedSearch(filter, page, limit) {
  const key = `search:${JSON.stringify(filter)}:${page}:${limit}`;
  const cached = await redisClient.get(key);
  if (cached) return JSON.parse(cached);
  const fresh = await searchProducts(filter, page, limit);
  await redisClient.setEx(key, 300, JSON.stringify(fresh)); // cache for 5 minutes
  return fresh;
}

