## 8. Implement the Vector Search Endpoint

```js
// server/routes/search.js
const router = require('express').Router();
const esClient = require('../search/elasticsearch');
const Article = require('../models/Article');
const { embed } = require('../search/embedding');
```

router.post('/', async (req, res) => {
  const { query, k = 10 } = req.body;
  const queryVector = await embed(query);

  const esResponse = await esClient.search({
    index: 'articles',
    size: k,
    body: {
      query: {
        script_score: {
          query: { match_all: {} },
          script: {
            source: "cosineSimilarity(params.queryVector, 'vector') + 1.0",
            params: { queryVector },
          },
        },
      },
    },
  });

  const ids = esResponse.body.hits.hits.map(hit => hit._id);
  const docs = await Article.find({ _id: { $in: ids } }).lean();

  // Preserve the order returned by ES
  const ordered = ids.map(id => docs.find(d => d._id.toString() === id));

  res.json(ordered);
});

module.exports = router;

